class Solution {
    public int minStable(int[] nums, int maxC) {
        int minStableFactor = Integer.MAX_VALUE;
        for (int i = 0; i < nums.length; i++) {
            int hcf = calculateHCF(nums, i);
            if (hcf >= 2 && nums[i] % hcf == 0) {
                int newNums[] = new int[nums.length];
                for (int j = i; j < nums.length; j++) {
                    if (nums[j] % hcf == 0) {
                        newNums[j] = nums[j];
                    }
                }
                if (minStableFactor < hcf) {
                    minStableFactor = hcf;
                }
            }
        }
        return minStableFactor;
    }

    private int calculateHCF(int[] nums, int i) {
        int hcf = 1;
        for (int j = i; j < nums.length; j++) {
            if (nums[j] % hcf == 0) {
                hcf = nums[j];
            }
        }
        return hcf;
    }
}
